<script setup lang="ts">
const reports=useAttendanceReports(); const feedback=useUiFeedback(); const loading=ref(false); const now=new Date(); const year=ref(now.getFullYear()); const month=ref(now.getMonth()+1); const summary=ref<any|null>(null)
async function refresh(){ loading.value=true; try{ summary.value=await reports.payrollSummary(year.value, month.value) }catch(e:any){ feedback.fromError('Attendance payroll summary failed',e) } finally{ loading.value=false } }
onMounted(refresh)
</script>
<template><AppShell title="Payroll Attendance Summary" @refresh="refresh"><section class="space-y-5"><UiModulePageHeader title="Payroll Attendance Summary" description="Attendance output for payroll review only. No automatic salary deduction in Stage 9B." icon="i-lucide-file-spreadsheet"><template #actions><UInput v-model="year" type="number" class="w-28"/><UInput v-model="month" type="number" class="w-24"/><UButton label="Refresh" :loading="loading" @click="refresh"/></template></UiModulePageHeader><div class="grid gap-3 md:grid-cols-5"><UCard><p class="text-xs text-muted">Employees</p><strong>{{ summary?.employees || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Present</p><strong>{{ summary?.presentDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Absent</p><strong>{{ summary?.absentDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Late</p><strong>{{ summary?.lateDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">OT Minutes</p><strong>{{ summary?.overtimeMinutes || 0 }}</strong></UCard></div><UAlert color="primary" title="Payroll integration note" description="Use this as review summary. Automatic payroll deduction/posting is scheduled for later package."/></section></AppShell></template>
